#include <stdio.h>
#include <string.h>

int isPalindrome(char *s, int start, int end) {
    while (start < end) {
        if (s[start] != s[end]) return 0;
        start++;
        end--;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[1001];
        scanf("%s", s);
        int n = strlen(s);
        int i, j;
        for (i = 0, j = n - 1; i < j; i++, j--) {
            if (s[i] != s[j]) {
                if (isPalindrome(s, i + 1, j)) {
                    printf("YES\n");
                    break;
                } else if (isPalindrome(s, i, j - 1)) {
                    printf("YES\n");
                    break;
                } else {
                    printf("NO\n");
                    break;
                }
            }
        }
        if (i >= j) printf("YES\n");
    }
    return 0;
}

